/**
 * User notification preferences model.
 *
 * Controls how and when a user receives email notifications.
 * Designed for email as the current channel, extensible for future channels.
 */

import type { NotificationType } from './notification.js';

/**
 * How often to receive email digests.
 * 'immediate' sends each notification as it happens.
 * 'daily' and 'weekly' batch notifications into digest emails.
 */
export type EmailFrequency = 'immediate' | 'daily' | 'weekly';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences>;
}

/**
 * Input for updating user preferences.
 */
export interface UpdateUserPreferencesInput {
  email?: Partial<EmailPreferences>;
}

/**
 * All notification types a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_update',
];

/**
 * Default email preferences for new users.
 */
export function getDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { EmailFrequency } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        subscribedCategories: JSON.parse(record['emailSubscribedCategories'] as string) as NotificationType[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedCategories: JSON.stringify(entity.email.subscribedCategories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user notification settings and a check
 * method that the notification service uses to decide whether to deliver.
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { getDefaultEmailPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepo: PreferencesRepository) {}

  /**
   * Create preferences for a user. Uses defaults for any omitted settings.
   * Throws if preferences already exist for the user.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    const existing = this.preferencesRepo.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const defaultEmail = getDefaultEmailPreferences();
    const now = new Date();

    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      email: {
        enabled: input.email?.enabled ?? defaultEmail.enabled,
        frequency: input.email?.frequency ?? defaultEmail.frequency,
        subscribedCategories: input.email?.subscribedCategories ?? defaultEmail.subscribedCategories,
      },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepo.save(preferences);
    this.logger.info(`Created preferences ${preferences.id} for user ${input.userId}`);
    return preferences;
  }

  /**
   * Get preferences for a user by user ID.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepo.findByUserId(userId);
  }

  /**
   * Update existing preferences for a user.
   * Throws if no preferences exist for the user.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    const existing = this.preferencesRepo.findByUserId(userId);
    if (!existing) {
      throw new Error(`No preferences found for user: ${userId}`);
    }

    const updated: UserPreferences = {
      ...existing,
      email: {
        enabled: input.email?.enabled ?? existing.email.enabled,
        frequency: input.email?.frequency ?? existing.email.frequency,
        subscribedCategories: input.email?.subscribedCategories ?? existing.email.subscribedCategories,
      },
      updatedAt: new Date(),
    };

    this.preferencesRepo.update(existing.id, updated);
    this.logger.info(`Updated preferences for user ${userId}`);
    return updated;
  }

  /**
   * Get or create preferences for a user. Returns existing if found,
   * otherwise creates with defaults.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepo.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return this.createPreferences({ userId });
  }

  /**
   * Check whether a notification should be delivered to a user on a given channel.
   *
   * Returns true if:
   * - No preferences exist (default: allow all)
   * - The channel is enabled AND the notification type is in subscribed categories
   */
  shouldNotify(userId: string, channel: NotificationChannel, type: NotificationType): boolean {
    const prefs = this.preferencesRepo.findByUserId(userId);

    // No preferences stored → default to allowing all notifications
    if (!prefs) {
      return true;
    }

    if (channel === 'email') {
      return prefs.email.enabled && prefs.email.subscribedCategories.includes(type);
    }

    // For channels without preferences support yet, allow by default
    return true;
  }

  /**
   * Delete preferences for a user.
   */
  deletePreferences(userId: string): boolean {
    const existing = this.preferencesRepo.findByUserId(userId);
    if (!existing) {
      return false;
    }
    return this.preferencesRepo.delete(existing.id);
  }
}

