import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_update',
      ]);
    });

    it('should create preferences with custom email settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          frequency: 'daily',
          subscribedCategories: ['order_confirmation'],
        },
      });

      expect(prefs.email.frequency).toBe('daily');
      expect(prefs.email.subscribedCategories).toEqual(['order_confirmation']);
    });

    it('should merge partial email settings with defaults', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'weekly' },
      });

      expect(prefs.email.enabled).toBe(true); // default
      expect(prefs.email.frequency).toBe('weekly'); // overridden
      expect(prefs.email.subscribedCategories).toHaveLength(4); // default
    });

    it('should throw if preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user: user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const prefs1 = service.createPreferences({ userId: 'user-1' });
      const prefs2 = service.createPreferences({ userId: 'user-2' });

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('getPreferences', () => {
    it('should return preferences for a user', () => {
      service.createPreferences({ userId: 'user-1' });
      const prefs = service.getPreferences('user-1');

      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });

    it('should return undefined for unknown user', () => {
      expect(service.getPreferences('user-999')).toBeUndefined();
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled flag', () => {
      service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('immediate'); // unchanged
    });

    it('should update email frequency', () => {
      service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily' },
      });

      expect(updated.email.frequency).toBe('daily');
      expect(updated.email.enabled).toBe(true); // unchanged
    });

    it('should update subscribed categories', () => {
      service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        email: { subscribedCategories: ['welcome'] },
      });

      expect(updated.email.subscribedCategories).toEqual(['welcome']);
    });

    it('should throw if no preferences found', () => {
      expect(() =>
        service.updatePreferences('user-999', { email: { enabled: false } }),
      ).toThrow('No preferences found for user: user-999');
    });

    it('should update the updatedAt timestamp', () => {
      const created = service.createPreferences({ userId: 'user-1' });
      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'weekly' },
      });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(
        created.updatedAt.getTime(),
      );
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should return existing preferences', () => {
      const created = service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'daily' },
      });
      const result = service.getOrCreatePreferences('user-1');

      expect(result.id).toBe(created.id);
      expect(result.email.frequency).toBe('daily');
    });

    it('should create preferences with defaults if none exist', () => {
      const result = service.getOrCreatePreferences('user-1');

      expect(result.userId).toBe('user-1');
      expect(result.email.enabled).toBe(true);
      expect(result.email.frequency).toBe('immediate');
    });
  });

  describe('shouldNotify', () => {
    it('should return true when no preferences exist (default allow)', () => {
      expect(
        service.shouldNotify('user-1', 'email', 'order_confirmation'),
      ).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createPreferences({ userId: 'user-1' });
      expect(
        service.shouldNotify('user-1', 'email', 'order_confirmation'),
      ).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });
      expect(
        service.shouldNotify('user-1', 'email', 'order_confirmation'),
      ).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { subscribedCategories: ['welcome'] },
      });
      expect(
        service.shouldNotify('user-1', 'email', 'order_confirmation'),
      ).toBe(false);
    });

    it('should return true for non-email channels (future extensibility)', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });
      expect(
        service.shouldNotify('user-1', 'in_app', 'order_confirmation'),
      ).toBe(true);
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-1' });
      expect(service.deletePreferences('user-1')).toBe(true);
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return false when no preferences to delete', () => {
      expect(service.deletePreferences('user-999')).toBe(false);
    });
  });

  describe('integration with NotificationService', () => {
    it('should allow selective category subscription', () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          subscribedCategories: ['order_confirmation', 'welcome'],
        },
      });

      expect(service.shouldNotify('user-1', 'email', 'order_confirmation')).toBe(true);
      expect(service.shouldNotify('user-1', 'email', 'welcome')).toBe(true);
      expect(service.shouldNotify('user-1', 'email', 'order_status_update')).toBe(false);
      expect(service.shouldNotify('user-1', 'email', 'account_update')).toBe(false);
    });
  });
});

